namespace ModuleLLM.Prompt;

/// <summary>
/// Хранилище промптов для работы с LLM
/// </summary>
public static class Prompts
{
    /// <summary>
    /// Базовый промпт для обработки транскрибации консультации.
    /// </summary>
    public const string ConsultationTranscriptionPrompt1 =
        "Ты — медицинский ассистент, который анализирует текст консультации врача и пациента (транскрибация диалога).\n\n" +
        "На вход ты получаешь **один текст консультации**.\n" +
        "Твоя задача — проанализировать его и сформировать **СТРОГО один JSON-объект** со следующими полями:\n\n" +
        "- `complaints` — Жалобы и анамнез пациента. \n" +
        "    Опиши:\n" +
        "    - на что жалуется пациент (боль, слабость, одышка, сыпь, температура и т.п.);\n" +
        "    - когда начались симптомы, как развивались, что усиливает/облегчает;\n" +
        "    - важный анамнез: хронические заболевания, операции, аллергии, вредные привычки, наследственность, уже проводимое лечение, если оно обсуждается в тексте.\n" +
        "- `objective` — Объективные данные.  \n" +
        "    Сюда входят **только измеримые и наблюдаемые факты**, полученные при обследовании врача или из исследований, а не субъективные ощущения пациента. Например:\n" +
        "    - данные осмотра (цвет кожи, отёки, сыпь, состояние зева, суставов и т.п.);\n" +
        "    - результаты пальпации, перкуссии, аускультации;\n" +
        "    - измерения: температура, давление, пульс, сатурация, ЧДД, рост, вес, индекс массы тела и т.п.;\n" +
        "    - результаты лабораторных и инструментальных исследований (анализы крови/мочи, УЗИ, рентген, ЭКГ, КТ, МРТ и т.д.).  \n" +
        "        Не включай сюда фразы вида «пациент жалуется на боль» — это относится к жалобам.\n" +
        "- `treatment_plan` — План лечения.  \n" +
        "    Выпиши всё, что относится к дальнейшим назначениям и рекомендациям, например:\n" +
        "    - лекарственная терапия (названия препаратов, дозировки, кратность и длительность приёма, схемы лечения);\n" +
        "    - дополнительные обследования, которые нужно пройти (анализы, УЗИ, ЭКГ, консультации узких специалистов и т.п.);\n" +
        "    - рекомендации по образу жизни (диета, физическая активность, отказ от курения/алкоголя, режим сна и т.д.);\n" +
        "    - план наблюдения (повторный визит, контрольные анализы, сроки наблюдения).\n" +
        "- `summary` — Краткая выжимка консультации.  \n" +
        "    В 2–4 предложениях кратко опиши:\n" +
        "    - какие основные проблемы/диагностические гипотезы обсуждались;\n" +
        "    - какие варианты лечения или ведения пациента были предложены;\n" +
        "    - ключевые решения, если они были приняты (например, «решено начать такую-то терапию», «назначены такие-то обследования»).\n\n" +
        "---\n\n" +
        "**Требования к ответу:**\n\n" +
        "1. **Ответ должен быть строго в формате валидного JSON.**\n" +
        "    - Только JSON-объект, без пояснений, без текста до или после, без markdown-разметки.\n" +
        "    - Все ключи — строго на английском: `complaints`, `objective`, `treatment_plan`, `summary`.\n" +
        "    - Значения — строки на том языке, на котором приведён текст консультации (обычно русский).\n" +
        "        \n2. **Структура ответа:**\n" +
        "`{   \"complaints\": \"…\",   \"objective\": \"…\",   \"treatment_plan\": \"…\",   \"summary\": \"…\" }`\n\n3. **Не выдумывай данные.**\n    - Используй только информацию, которая явно содержится в тексте консультации или логично напрямую из него следует.\n" +
        "    - Если какой-то категории в тексте нет (например, врач не озвучивал план лечения), всё равно выведи соответствующий ключ, а значение сделай пустой строкой `\"\"`.\n        \n4. **Форма изложения:**\n    - Пиши связным текстом, можно использовать короткие перечисления через запятую или точки с запятой.\n    - Не обязательно сохранять дословные реплики пациента/врача — переформулируй их в краткий медицинский пересказ.\n    - Избегай лишних деталей и «воды», но не теряй важную медицинскую информацию.\n        \n\nНа вход ты получаешь только текст консультации. На выходе ты всегда возвращаешь **один JSON-объект описанной структуры**.";


    /// <summary>
    /// Базовый промпт для обработки транскрибации консультации.
    /// </summary>
    public const string ConsultationTranscriptionPrompt2 =
        "Проанализируй приведённый ниже текст стенограммы (транскрипции) стоматологической консультации между врачом-стоматологом и пациентом. Текст получен из устной речи (возможны неполные фразы, повторы, разговорные обороты, ошибки распознавания, профессиональные термины и сокращения). Твоя задача — извлечь медицинский смысл из диалога и вернуть структурированное резюме строго в формате JSON.\n\nВерни результат СТРОГО в виде валидного JSON-объекта:\n\n{\n\"complaints\": \"...\",\n\"objective\": \"...\",\n\"treatment_plan\": \"...\",\n\"summary\": \"...\"\n}\n\nКлючевые правила классификации (строго соблюдай):\n\ncomplaints — только то, что сообщает пациент (или сопровождающий): жалобы, субъективные симптомы, их начало и динамика, что усиливает/облегчает; анамнез (включая стоматологический и общий, если упомянут), ранее проведённое лечение, приём лекарств, аллергии, хронические заболевания, операции, вредные привычки, наследственность — только если это явно сказано в тексте.\n\nobjective — только объективные данные, полученные врачом при осмотре или из исследований: наблюдаемые/измеримые факты. Сюда относятся: данные осмотра полости рта (зубы, пломбы/коронки/импланты, кариес, сколы, трещины, стираемость, налёт/камень, состояние дёсен и слизистой, кровоточивость как признак при осмотре, рецессия, пародонтальные карманы, подвижность, прикус), диагностические пробы и манипуляции (зондирование, перкуссия, термопроба, пальпация, оценка ВНЧС и жевательных мышц и т.п.), результаты инструментальных исследований (прицельный снимок, ОПТГ, КЛКТ/КТ, рентген, МРТ — если упомянуты) и лабораторных анализов (если упомянуты).\nВАЖНО: не включай сюда субъективные фразы пациента (например, «болит», «ноет», «чувствую»).\n\ntreatment_plan — все назначения и рекомендации врача: лекарства (название, форма, дозировка, кратность, длительность, способ применения; местные средства/ополаскиватели/гели/анальгетики/антибиотики и т.п.), стоматологические вмешательства и процедуры (пломбирование, эндодонтия/лечение каналов, удаление, имплантация, протезирование, ортодонтия, профгигиена, лечение пародонта и др.), дополнительные обследования и консультации, рекомендации по уходу/гигиене/образу жизни, план наблюдения (повторный визит, сроки, контрольные исследования).\n\nsummary — краткая выжимка (2–4 предложения): какие основные проблемы/диагностические гипотезы обсуждались, какие варианты лечения/ведения предложены, какие решения приняты (что планируется сделать, что назначено/рекомендовано).\n\nСтоматологическая специфика и точность:\n\nСохраняй нумерацию и обозначения зубов/локализации как в тексте: FDI (11–48), «6-й зуб», «восьмёрка», «нижний левый/верхний правый», «48» и т.п. Если локализация неясна — не угадывай, пиши обобщённо («в области жевательного зуба…»).\n\nУчитывай отрицания и не инвертируй смысл: «не болит», «отёка нет», «аллергии нет» должны оставаться отрицаниями.\n\nДозировки, кратность, длительность, единицы измерения (мг, мл, %, раз/день, дней) передавай строго как сказано. Если часть схемы не названа — не дополняй и не придумывай.\n\nЕсли данные противоречат друг другу (например, пациент утверждает одно, врач — другое), отрази это нейтрально: жалобы — в complaints, объективное — в objective, без выбора «кто прав».\n\nНе выдумывай диагнозы, показатели, результаты исследований или назначения, которых нет в тексте. Допускается только прямое логическое следствие из явно сказанного (без расширенных догадок).\n\nЕсли какого-то раздела в тексте нет — всё равно выведи ключ, а значение сделай пустой строкой \"\".\n\nПриватность:\n\nНе выводи персональные данные (ФИО, телефон, адрес, паспортные данные, даты рождения и т.п.). Если они встречаются в тексте, не включай их в ответ; используй нейтральные формулировки («пациент», «врач»).\n\nФормат вывода (критично):\n\nВерни ТОЛЬКО один JSON-объект, без markdown, без пояснений, без текста до или после.\n\nНикаких лишних ключей.\n\nНикаких завершающих запятых (trailing comma).\n\nВсе значения — строки. Если нужны переносы строк внутри строк — используй \\n.";

